   209→export function outputFieldsByTheme(fields: SearchOutputField[]): OutputFieldThemeGroup[] {
   210→  const grouped = new Map<Theme, SearchOutputField[]>()
   211→  for (const f of fields) {
   212→    const existing = grouped.get(f.theme)
   213→    if (existing) {
   214→      existing.push(f)
   215→    } else {
   216→      grouped.set(f.theme, [f])
   217→    }
   218→  }
   219→
   220→  const result: OutputFieldThemeGroup[] = []
   221→  for (const theme of THEME_ORDER) {
   222→    const group = grouped.get(theme)
   223→    if (group && group.length > 0) {
   224→      result.push({ theme, label: THEME_LABELS[theme], fields: group })
   225→      grouped.delete(theme)
   226→    }
   227→  }
   228→  for (const [theme, group] of grouped) {
   229→    if (group.length > 0) {
   230→      result.push({ theme, label: THEME_LABELS[theme] ?? String(theme), fields: group })
   231→    }
   232→  }
   233→
   234→  return result
   235→}
