	Lng      float64 `json:"lng"`
	RadiusKm float64 `json:"radius_km"`
}

// GeoBoundingBoxFilter specifies an axis-aligned geographic bounding box.
type GeoBoundingBoxFilter struct {
	MinLat float64 `json:"min_lat"`
	MaxLat float64 `json:"max_lat"`
	MinLng float64 `json:"min_lng"`
	MaxLng float64 `json:"max_lng"`
}

// GeoFilterInput is the top-level geo filter that wraps the specific kind.
type GeoFilterInput struct {
	Kind   GeoFilterKind        `json:"kind"`
	Radius *GeoRadiusFilter     `json:"radius,omitempty"`
	BBox   *GeoBoundingBoxFilter `json:"bbox,omitempty"`
}

