// TestOutputDescriptors_KnownValues spot-checks the outputDefault and sortable
// flags for a representative set of fields.
func TestOutputDescriptors_KnownValues(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	cases := []struct {
		name            string
		wantOutput      bool // true = is an output field (OutputDefault != nil)
		wantDefault     bool // expected *OutputDefault when wantOutput=true
		wantSortable    bool
	}{
		// Default-visible output fields
		{"name", true, true, true},
		{"city", true, true, true},
		{"state", true, true, true},
		{"enrollment", true, true, true},
		{"institution_type", true, true, false},
		// Available-but-not-default output fields
		{"admission_rate", true, false, true},
		{"tuition_in_state", true, false, true},
		{"rank_us_news_national", true, false, true},
		{"ncaa_conference", true, false, false},
		// Input-only fields — not output fields
		{"location", false, false, false},
		{"carnegie_basic", false, false, false},
		{"congressional_district", false, false, false},
		{"fields_of_study", false, false, false},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			f, ok := reg.Lookup(tc.name)
			if !ok {
				t.Fatalf("field %q not found in registry", tc.name)
			}
			d := f.Descriptor()

			isOutput := d.OutputDefault != nil
			if isOutput != tc.wantOutput {
				t.Errorf("field %q: isOutputField = %v, want %v", tc.name, isOutput, tc.wantOutput)
			}
			if tc.wantOutput && isOutput {
				if *d.OutputDefault != tc.wantDefault {
					t.Errorf("field %q: OutputDefault = %v, want %v", tc.name, *d.OutputDefault, tc.wantDefault)
				}
			}
			if d.Sortable != tc.wantSortable {
				t.Errorf("field %q: Sortable = %v, want %v", tc.name, d.Sortable, tc.wantSortable)

