// TestSearchFields_ReturnsAllVisibleFields verifies the count matches visible
// descriptors (excludes HIDDEN fields which are never returned).
func TestSearchFields_ReturnsAllVisibleFields(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	r := newTestSearchFieldsResolver()

	// Use authenticated context to include RESTRICTED fields.
	fields, err := r.SearchFields(authContext())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	// Count non-HIDDEN descriptors — HIDDEN fields are never returned.
	want := 0
	for _, d := range reg.Descriptors() {
		if d.Visibility != search.VisibilityHidden {
			want++
		}
	}
	if len(fields) != want {
		t.Errorf("len(fields) = %d, want %d (visible descriptors)", len(fields), want)
	}
}

// TestSearchFields_BinaryDetection verifies online_only maps to BinarySearchField.
func TestSearchFields_BinaryDetection(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	fields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields returned error: %v", err)
	}

	f := findFieldByName(t, fields, "online_only")
	if _, ok := f.(*model.BinarySearchField); !ok {
		t.Errorf("online_only: got %T, want *model.BinarySearchField", f)
