	// fields have OutputDefault set (e.g. location, fields_of_study are input-only).
	allCount := len(reg.Descriptors())
	if len(outFields) >= allCount {
		t.Errorf("output fields count %d >= all descriptors %d; some should be input-only",
			len(outFields), allCount)
	}
}

