	r := newTestSearchFieldsResolver()

	allFields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields error: %v", err)
	}
	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	if len(outFields) == 0 {
		t.Fatal("SearchOutputFields returned empty slice")
	}
	if len(outFields) >= len(allFields) {
		t.Errorf("output fields count %d >= all fields count %d; some should be input-only",
			len(outFields), len(allFields))
	}
}

