// TestSearchOutputFields_SharedMetadata verifies that name/label/visibility/exportable
// match their counterparts in SearchFields for a representative field.
func TestSearchOutputFields_SharedMetadata(t *testing.T) {
	t.Parallel()
	r := newTestSearchFieldsResolver()

	allFields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields error: %v", err)
	}
	outFields, err := r.SearchOutputFields(context.Background())
	if err != nil {
		t.Fatalf("SearchOutputFields error: %v", err)
	}

	// Find "enrollment" in both slices.
	inputEnrollment := findFieldByName(t, allFields, "enrollment")
	nrf, ok := inputEnrollment.(*model.NumericalRangeSearchField)
	if !ok {
		t.Fatalf("enrollment in SearchFields: got %T, want NumericalRangeSearchField", inputEnrollment)
	}

	var outputEnrollment *model.SearchOutputField
	for _, f := range outFields {
		if f.Name == "enrollment" {
			outputEnrollment = f
			break
		}
	}
	if outputEnrollment == nil {
		t.Fatal("enrollment missing from SearchOutputFields")
	}

	// Shared metadata must match.
	if outputEnrollment.Label != nrf.Label {
		t.Errorf("enrollment label mismatch: input=%q output=%q", nrf.Label, outputEnrollment.Label)
	}
	if outputEnrollment.Visibility != nrf.Visibility {
		t.Errorf("enrollment visibility mismatch: input=%v output=%v", nrf.Visibility, outputEnrollment.Visibility)
	}
	if outputEnrollment.Exportable != nrf.Exportable {
		t.Errorf("enrollment exportable mismatch: input=%v output=%v", nrf.Exportable, outputEnrollment.Exportable)
	}
}

// TestSearchFields_AnonExcludesHidden verifies that anonymous context excludes
// HIDDEN fields, resulting in fewer fields than the full descriptor list.
func TestSearchFields_AnonExcludesHidden(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()
	r := newTestSearchFieldsResolver()

	anonFields, err := r.SearchFields(context.Background())
	if err != nil {
		t.Fatalf("SearchFields (anon) returned error: %v", err)
	}
	authFields, err := r.SearchFields(authContext())
	if err != nil {
		t.Fatalf("SearchFields (auth) returned error: %v", err)
	}

	// Both should exclude HIDDEN; since there are no RESTRICTED fields in the
	// current registry, anon and auth counts should be equal.
	hiddenCount := 0
	for _, d := range reg.Descriptors() {
		if d.Visibility == search.VisibilityHidden {
			hiddenCount++
		}
	}
	if hiddenCount == 0 {
		t.Fatal("expected at least one HIDDEN field in the registry")
	}

	allCount := len(reg.Descriptors())
	if len(anonFields) != allCount-hiddenCount {
		t.Errorf("anon field count = %d, want %d (all %d - hidden %d)",
			len(anonFields), allCount-hiddenCount, allCount, hiddenCount)
	}
	if len(authFields) != allCount-hiddenCount {
		t.Errorf("auth field count = %d, want %d", len(authFields), allCount-hiddenCount)
	}
}

// TestSearchOutputFields_MultiEnum verifies a multi-enum field has no MaxSelections cap.
func TestSearchFields_MultiEnum(t *testing.T) {
